mapper.update:
/* wms-outbound-etcexpt-sql-oracle.xml - etcExptIvAdMvUpdate - 기타반출 - 재고관리자이동내역 update */
UPDATE TWORK_INFO_IV_AD_MOVE
   SET EXPTRSNCD = #{exptrsncd}
     , EXPTRSNDTCONT = #{exptrsndtcont}
	 , EXPTQTY = EXPTQTY + #{inputqty}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND SEQNO = #{seqno}

mapper.sql:
/* wms-outbound-etcexpt-sql-oracle.xml - etcExptIvSql - 기타반출 - 로케이션별 재고정보 조회 SQL */ SELECT IVLC.CTKEY /*센터 코드*/ , CT.CTNM /*센터명*/ , IVLC.OWKEY /*화주 코드*/ , ZN.ZNNM /*존명*/ , AR.ARNM /*구역명*/ , IVLC.LCKEY /*로케이션 코드*/ , IVLC.ICKEY /*상품코드*/ , IC.ICNM /*상품명*/ , IVLC.TOTQTY /*총수량*/ , IVLC.AVQTY /*가용수량*/ , IVLC.ALQTY /*할당수량*/ , IVLC.HOLDQTY /*보류수량*/ , (IVLC.TOTQTY * IC.SLPRC) AS SLPRC /*금액*/ , IVLC.INSERTDATE /*입력 일시*/ , IVLC.INSERTURKEY /*입력 사용자 ID*/ , IVLC.UPDATEDATE /*수정 일시*/ , IVLC.UPDATEURKEY /*수정 사용자 ID*/ FROM TWORK_INFO_IVATXLC IVLC /*재고 속성별 로케이션별 재고 정보*/ INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON IVLC.CTKEY = IC.CTKEY AND IVLC.OWKEY = IC.OWKEY AND IVLC.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICBARCODE ICB /*상품바코드 마스터*/ ON IC.CTKEY = ICB.CTKEY AND IC.OWKEY = ICB.OWKEY AND IC.ICKEY = ICB.ICKEY INNER JOIN TWORK_MST_LC LC /*로케이션 마스터*/ ON IVLC.CTKEY = LC.CTKEY AND IVLC.LCKEY = LC.LCKEY INNER JOIN TWORK_MST_AR AR /*구역 마스터*/ ON LC.CTKEY = AR.CTKEY AND LC.ZNKEY = AR.ZNKEY AND LC.ARKEY = AR.ARKEY INNER JOIN TWORK_MST_ZN ZN /*존 마스터*/ ON AR.CTKEY = ZN.CTKEY AND AR.ZNKEY = ZN.ZNKEY INNER JOIN TWORK_MST_CT CT /*센터 마스터*/ ON ZN.CTKEY = CT.CTKEY
#{SEARCH_CONDITION}
AND ICB.UOM = 'EA' AND ZN.ZNKEY IN ('DFS', 'DMS', 'DNS', 'DFR', 'DMR', 'DNR', 'DMN', 'DMG') /*DFS: 센터내불량존, DMS: 센터내파손존, DNS: 센터내기부존, DFR:고객반품불량존, DMR: 고객반품파손존, DNR: 고객반품기부존, DMN: 고객반품미회수존, DMG: 고객반품파손-식품존 */

